import{_ as t,o as a,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Import a Spreadsheet","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/spreadsheet-import.md","filePath":"how-to/spreadsheet-import.md"}'),i={name:"how-to/spreadsheet-import.md"};function l(s,e,p,h,d,n){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="import-a-spreadsheet" tabindex="-1">Import a Spreadsheet <a class="header-anchor" href="#import-a-spreadsheet" aria-label="Permalink to &quot;Import a Spreadsheet&quot;">​</a></h1><p>Spreadsheet import is the file-based alternative to screenshot OCR when you already have event rows in <code>.xlsx</code>, <code>.xls</code>, or <code>.csv</code> form.</p><blockquote><p>Screenshot placeholder: spreadsheet-upload.png</p></blockquote><h2 id="what-the-page-supports" tabindex="-1">What the page supports <a class="header-anchor" href="#what-the-page-supports" aria-label="Permalink to &quot;What the page supports&quot;">​</a></h2><p>The spreadsheet panel lets you:</p><ul><li>choose a file</li><li>adjust a field-mapping JSON</li><li>preview the mapped rows</li><li>apply the import and open its review page</li></ul><h2 id="preview-first" tabindex="-1">Preview first <a class="header-anchor" href="#preview-first" aria-label="Permalink to &quot;Preview first&quot;">​</a></h2><p>The safest first step is <strong>Preview</strong>.</p><p>Preview shows mapped rows such as:</p><ul><li>player</li><li>event</li><li>date</li><li>score</li><li>participation status</li><li>whether review is likely needed</li></ul><p>This does not open live result rows yet.</p><h2 id="what-apply-import-really-does" tabindex="-1">What &quot;Apply import&quot; really does <a class="header-anchor" href="#what-apply-import-really-does" aria-label="Permalink to &quot;What &quot;Apply import&quot; really does&quot;">​</a></h2><p>When you choose <strong>Apply import</strong>:</p><ul><li>the app creates an import record</li><li>it creates review rows</li><li>it opens the import review page</li></ul><p>So spreadsheet import still leads into the same review-and-accept workflow used by screenshot imports.</p><h2 id="context-still-matters" tabindex="-1">Context still matters <a class="header-anchor" href="#context-still-matters" aria-label="Permalink to &quot;Context still matters&quot;">​</a></h2><p>Before applying, make sure you chose the correct:</p><ul><li>kingdom</li><li>alliance, when needed</li><li>event</li><li>date</li><li>stage or total mode, when needed</li></ul><p>The spreadsheet panel uses the same event context as the rest of the imports page.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>preview first, especially when using a custom mapping</li><li>keep one spreadsheet focused on one event/date context</li><li>treat the review page as part of the workflow, not an optional extra</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../imports/overview.html">How Screenshot Imports Work</a></li><li><a href="./../imports/review-rows.html">Review Import Rows</a></li><li><a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a></li></ul>',23)])])}const u=t(i,[["render",l]]);export{m as __pageData,u as default};
